doc-style.content:
.rendered-preview,
#visual-editor {
  background: #faf1e2;
  color: #251913;
  border-radius: 10px;
  padding: 1rem;
  box-shadow: inset 0 0 0 1px rgba(0, 0, 0, 0.08);
}

.rendered-preview h1,
.rendered-preview h2,
.rendered-preview h3,
.rendered-preview h4,
.rendered-preview h5,
.rendered-preview h6,
#visual-editor h1,
#visual-editor h2,
#visual-editor h3,
#visual-editor h4,
#visual-editor h5,
#visual-editor h6 {
  color: #8c2f1f;
}

.rendered-preview a,
#visual-editor a,
.rendered-preview strong,
#visual-editor strong {
  color: #d9b46b;
}

.rendered-preview code,
#visual-editor code {
  background: rgba(0, 0, 0, 0.08);
  padding: 0.1rem 0.3rem;
  border-radius: 4px;
}

.rendered-preview blockquote,
#visual-editor blockquote,
.rendered-preview .monster-stat-block,
#visual-editor .monster-stat-block {
  border-left: 4px solid #d9b46b;
  background: rgba(255, 255, 255, 0.6);
  padding: 0.75rem 1rem;
  margin: 0.75rem 0;
}

.rendered-preview img,
#visual-editor img {
  max-width: 100%;
  border-radius: 8px;
}

.rendered-preview .wrap-left img,
#visual-editor .wrap-left img {
  float: left;
  max-width: 38%;
  margin: 0 1rem 0.75rem 0;
}

